import React, { useState } from 'react';
import QRCode from 'qrcode';

/**
 * Componente principal do convite digital
 * Contém toda a lógica de interação e exibição do convite
 */
const InviteCard = () => {
  // Estado para armazenar o nome do convidado
  const [nome, setNome] = useState('');
  
  // Estado para controlar a mensagem de confirmação
  const [mensagem, setMensagem] = useState('');
  
  // Estado para controlar o QR Code PIX
  const [showPix, setShowPix] = useState(false);
  const [qrCodeUrl, setQrCodeUrl] = useState('');
  
  // Estado para tipo de ingresso
  const [tipoIngresso, setTipoIngresso] = useState('sozinho'); // 'sozinho' ou 'casal'

  /**
   * Manipula o clique no botão "Confirmar e pagar agora"
   * Exibe mensagem de pagamento e gera QR Code PIX
   */
  const handleConfirmarPagar = async () => {
    if (nome.trim()) {
      const valor = tipoIngresso === 'sozinho' ? '35,00' : '50,00';
      setMensagem(`Pagamento iniciado para ${nome} - R$ ${valor} (simulação)`);
      
      // Salva no localStorage para o painel admin
      const convidado = {
        id: Date.now(),
        nome: nome,
        tipo: tipoIngresso,
        valor: valor,
        status: 'pendente',
        data: new Date().toLocaleDateString('pt-BR')
      };
      
      // Salva no localStorage
      const convidadosSalvos = JSON.parse(localStorage.getItem('convidados') || '[]');
      convidadosSalvos.push(convidado);
      localStorage.setItem('convidados', JSON.stringify(convidadosSalvos));
      
      // Gera QR Code PIX
      const pixPayload = `00020126580014br.gov.bcb.pix0136+5551936624145204000053039865404${valor.replace(',', '.')}5802BR5925PROJETO X 1.0 - Festa 186009SAO PAULO62070503***6304${Math.random().toString().substr(2, 4)}`;
      
      try {
        const qrDataUrl = await QRCode.toDataURL(pixPayload);
        setQrCodeUrl(qrDataUrl);
        setShowPix(true);
      } catch (err) {
        console.error('Erro ao gerar QR Code:', err);
      }
    } else {
      setMensagem('Por favor, digite seu nome');
    }
  };

  /**
   * Manipula o clique no botão "Reservar e pagar depois"
   * Exibe mensagem de reserva simulada
   */
  const handleReservar = () => {
    if (nome.trim()) {
      setMensagem(`Reserva registrada para ${nome} (simulação)`);
    } else {
      setMensagem('Por favor, digite seu nome');
    }
  };

  return (
    <div className="w-full max-w-md">
      {/* Card principal com efeito de vidro fosco */}
      <div className="backdrop-blur-md bg-zinc-900/60 border border-zinc-700 rounded-2xl shadow-xl p-8">
        <div className="text-center space-y-6">
          {/* Texto pequeno superior */}
          <p className="text-zinc-400 text-sm tracking-widest uppercase">
            VOCÊ FOI CONVIDADO PARA
          </p>

          {/* Título principal */}
          <h1 className="text-white text-4xl md:text-5xl font-bold tracking-wide">
            PROJETO X 1.0
          </h1>

          {/* Subtítulo */}
          <h2 className="text-zinc-300 text-xl md:text-2xl font-medium tracking-wide">
            Festa de 18 anos
          </h2>

          {/* Texto informativo */}
          <div className="text-zinc-400 text-sm space-y-2 text-left bg-zinc-800/30 rounded-lg p-4">
            <p className="tracking-wide">
              <span className="text-zinc-300 font-medium">Data:</span> do dia 30 para o dia 31.
            </p>
            <p className="tracking-wide">
              <span className="text-zinc-300 font-medium">Horário:</span> das 21h30 até o amanhecer.
            </p>
            <p className="tracking-wide">
              <span className="text-zinc-300 font-medium">Local:</span> em breve – estamos definindo um espaço grande.
            </p>
            <p className="tracking-wide">
              <span className="text-zinc-300 font-medium">Informações:</span> open bar.
            </p>
            <p className="tracking-wide">
              <span className="text-zinc-300 font-medium">valor:</span> 1 pessoa = R$ 35,00. 2 pessoas = R$ 50,00.
            </p>
          </div>

          {/* Input para nome do convidado */}
          <div className="space-y-2">
            <input
              type="text"
              value={nome}
              onChange={(e) => setNome(e.target.value)}
              placeholder="Digite seu nome completo"
              className="w-full px-4 py-3 bg-zinc-800/50 border border-zinc-600/50 rounded-lg text-white placeholder-zinc-500 focus:outline-none focus:ring-2 focus:ring-zinc-500 focus:border-transparent transition-all duration-300"
            />
          </div>

          {/* Tipo de ingresso */}
          <div className="space-y-2">
            <p className="text-zinc-300 text-sm font-medium tracking-wide">
              Tipo de ingresso:
            </p>
            <div className="grid grid-cols-2 gap-3">
              <button
                onClick={() => setTipoIngresso('sozinho')}
                className={`py-2 px-4 rounded-lg font-medium transition-all duration-300 ${
                  tipoIngresso === 'sozinho'
                    ? 'bg-zinc-100 text-zinc-900 border-2 border-zinc-300'
                    : 'bg-zinc-800/50 border border-zinc-600/50 text-zinc-300 hover:bg-zinc-700/50'
                }`}
              >
                1 pessoa
                <span className="block text-xs mt-1">R$ 35,00</span>
              </button>
              <button
                onClick={() => setTipoIngresso('casal')}
                className={`py-2 px-4 rounded-lg font-medium transition-all duration-300 ${
                  tipoIngresso === 'casal'
                    ? 'bg-zinc-100 text-zinc-900 border-2 border-zinc-300'
                    : 'bg-zinc-800/50 border border-zinc-600/50 text-zinc-300 hover:bg-zinc-700/50'
                }`}
              >
                Casal
                <span className="block text-xs mt-1">R$ 50,00</span>
              </button>
            </div>
          </div>

          {/* Botões de ação */}
          <div className="space-y-3">
            <button
              onClick={handleConfirmarPagar}
              className="w-full py-3 px-6 bg-zinc-100 text-zinc-900 font-medium rounded-lg hover:bg-zinc-200 transform hover:scale-105 transition-all duration-300 shadow-lg hover:shadow-xl"
            >
              Confirmar e pagar agora
            </button>
            <button
              onClick={handleReservar}
              className="w-full py-3 px-6 bg-transparent border border-zinc-400 text-zinc-300 font-medium rounded-lg hover:bg-zinc-800/50 hover:border-zinc-300 hover:text-white transform hover:scale-105 transition-all duration-300"
            >
              Reservar e pagar depois
            </button>
          </div>
        </div>
      </div>

      {/* Mensagem de confirmação (exibida abaixo do card) */}
      {mensagem && (
        <div className="mt-6 p-4 bg-zinc-800/60 border border-zinc-700 rounded-lg backdrop-blur-md">
          <p className="text-zinc-300 text-center tracking-wide">
            {mensagem}
          </p>
        </div>
      )}

      {/* Modal QR Code PIX */}
      {showPix && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center p-4 z-50">
          <div className="bg-zinc-900 border border-zinc-700 rounded-2xl p-6 max-w-sm w-full">
            <div className="text-center space-y-4">
              <h3 className="text-white text-xl font-bold tracking-wide">
                QR Code PIX
              </h3>
              
              <p className="text-zinc-400 text-sm">
                Escaneie o QR Code para pagar R$ {tipoIngresso === 'sozinho' ? '35,00' : '50,00'}
              </p>

              {/* QR Code */}
              {qrCodeUrl && (
                <div className="bg-white p-4 rounded-lg inline-block">
                  <img 
                    src={qrCodeUrl} 
                    alt="QR Code PIX" 
                    className="w-48 h-48"
                  />
                </div>
              )}

              {/* Chave PIX */}
              <div className="bg-zinc-800/50 border border-zinc-600/50 rounded-lg p-3">
                <p className="text-zinc-400 text-xs mb-1">Chave PIX:</p>
                <p className="text-white font-mono text-sm">+55 51 9366-2414</p>
              </div>

              {/* Botão fechar */}
              <button
                onClick={() => setShowPix(false)}
                className="w-full py-2 px-4 bg-zinc-700 text-white font-medium rounded-lg hover:bg-zinc-600 transition-all duration-300"
              >
                Fechar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default InviteCard;
